var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저 쪽에서 총소리가 들렸습니다! 모두 조심하세요!","JPN":"向こうから銃声が聞こえました！　皆さん気を付けてください！","ENG":"I heard a gunshot from over there! Everyone, be careful!","TWN":"那邊傳出槍聲！大家小心！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음? 잠깐, 저 사람은 를르슈잖아?","JPN":"うん？　待って、あれはルルーシュ？","ENG":"Hmm? Hold on, isn't that Lelouch?","TWN":"嗯？那個人，不是魯路修嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고…… 저건 타피르……?","JPN":"それに、あれはタピルなの？","ENG":"And also... Tapir...?","TWN":"另一個是……達爾……？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐…… 타피르 선배? 그 눈은 뭐야……?","JPN":"えっ……、タピル先輩？　その目はなに……？","ENG":"Huh...? Tapir? What happened to your eyes...?","TWN":"什麼……達爾前輩？他的眼睛怎麼……？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이게 무슨 일이야? 도대체 뭐가 어떻게 돌아가는 건데?","JPN":"これはどういうこと？　いったい何が起きてるっていうの！？","ENG":"What just happened? What's going on here?","TWN":"怎麼會這樣？到底發生什麼事？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"대단하군요. 를르슈.","JPN":"すごいですね、ルルーシュ。","ENG":"Impressive, Lelouch.","TWN":"算你厲害，魯路修。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"분명, 수없이 기억이 리셋됐을 텐데 어떻게 제 정체를 간파해낸 거죠?","JPN":"数え切れないほど記憶がリセットされたはずなのに、\\nどうして僕の正体を見抜けたのですか？","ENG":"I'm certain your memory was reset countless times. How did you manage to figure out it was me?","TWN":"我明明就有重置過好幾次記憶，你是怎麼識破我的？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"말하지 않았나. 처음부터 이 세계 자체가 거짓이었다는 걸 눈치채고 있었다고.","JPN":"言っただろう。最初から、この世界自体が偽物だということに気づいていたと。","ENG":"Didn't I say? I knew this world was a lie from the start.","TWN":"我沒說嗎？我打從一開始就知道這個世界是假的。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그러니까, 나에게 필요한 건 정보였어. 이레귤러를 구분할 수 있는 정보.","JPN":"だから、俺に必要なのは情報だった。イレギュラーを見分ける情報だ。","ENG":"That's why I needed to gather information. To sniff out the Irregular.","TWN":"所以我需要的是資訊，可以分辨不規律的資訊。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"이레귤러……!?","JPN":"イレギュラー……！？","ENG":"The Irregular...?!","TWN":"不規律……！？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇구나, 그래서 를르슈는 나한테 그런 쪽지를…….","JPN":"なるほど、だからルルーシュは私にあのメモを……","ENG":"Now I get it. That's why you left me that note...","TWN":"原來是這樣，所以你才會給我那張紙條……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그래, 유미나. 간단히 말해서, 이건 일종의 편 가르기야.","JPN":"そうだ、ミナ。簡単に言えば、これは一種の仲間分けだ。","ENG":"Yes, Yoo Mina. To put it simply, I was distinguishing friend from foe.","TWN":"沒錯，劉米娜。簡單來說，我在分類。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"타피르가 어떤 방법으로 우리들에게 거짓 기억을 심었는지는 몰라. 하지만 녀석이 심어둔 기억과 우리들의 원래 기억은 차이가 있지.","JPN":"やつがどんな方法で俺たちに偽りの記憶を植え付けたのかはわからない。\\nしかし、タピルが仕込んだ設定と俺たちの本来の記憶にはズレがある。","ENG":"I don't know how Tapir planted false memories in our minds. But those memories and our original ones are different.","TWN":"雖然不知道達爾是用什麼方法植入假記憶的，但他植入的記憶和我們原本的記憶，一定多少有落差。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"녀석이 심은 기억에서는 우리 모두 사이좋은 애쉬포드 학원의 학생회 멤버……라고 설정되어 있어.","JPN":"タピルが作り上げた設定で、俺たちはみんな、\\n仲が良いアッシュフォード学園の生徒会メンバー、ということになった。","ENG":"The planted memories state... that we are all good friends of the Student Council at Ashford Academy.","TWN":"在他植入的記憶中，設定我們是一群感情很好的阿什弗德學院學生會成員……。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 이 중에 진짜 애쉬포드 학생회 멤버는 나와 셜리 그리고 카렌 뿐이야.","JPN":"しかし、この中に本物の生徒会メンバーは\\n俺とシャーリー、そしてカレンしかいない。","ENG":"But the real Ashford Student Council members are me, Shirley, and Kallen.","TWN":"但實際上，在這當中只有我、 夏麗和卡蓮是真的阿什弗德學生會成員。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나, 너를 포함한 다른 네 사람은 애쉬포드 학원과는 전혀 관계없는 사람이지.","JPN":"ミナ、お前を含めて残りの4人は\\nアッシュフォード学園とは全く関係のない人間だ。","ENG":"The remaining four, which also includes you, Mina, have nothing to do with Ashford.","TWN":"米娜，包括你在內的其餘四個人，與阿什弗德學院一點關係也沒有。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"무슨 헛소리야!? 우리가 애쉬포드 학생이 아니라면……","JPN":"何バカなこと言ってるの！？\\n私たちがアッシュフォード学園の生徒じゃないなら……","ENG":"What are you talking about?! If we're not Ashford students, then...","TWN":"你在胡說什麼！？我們不是阿什弗德的學生的話……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니라면…… 어, 어라? 아니었던 것 같기도 하고……!?","JPN":"じゃないなら……あ、あれ？　じゃなかったような……！？","ENG":"Then... H-huh? Maybe I really wasn't...?!","TWN":"的話……嗯？好像真的不是欸……！？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"읏, 머리가…… 머리가 울리는 군요.","JPN":"ううっ、頭が……頭が痛いですね。","ENG":"Ngh, my head... It's throbbing.","TWN":"唔，我的頭……嗡嗡作響。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 애쉬포드 학원이라는 곳이 실제로 존재했단 말이야? 너희는 그곳 학생이고?","JPN":"じゃあ、アッシュフォード学園は実際に存在していたってことなの？\\nあなたたちはそこの生徒だったの？","ENG":"Then Ashford Academy is a place that really exists? And you are all students attending there?","TWN":"所以意思是阿什弗德學院是真實存在的嗎？你們是那裡的學生？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아아, 애쉬포드 학원은 우리들이 살던 세계에 실제로 있는 곳이야.","JPN":"ああ……そうだ。\\nアッシュフォード学園は、俺たちのいた世界に実在した。","ENG":"Yes. Ashford is a real place back in my world.","TWN":"阿什弗德學院在我們生活的世界裡是真實存在的。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};